{
  "name": "CoachingByLene",
  "description": "A professional and modern website for Lene Vindelev D. Nielsen's private coaching business, featuring her credentials, specialties, and a specialized appointment booking system."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BookingFormData {
  fullName: string;
  email: string;
  day: string;
  time: string;
  description: string;
}

export interface Specialty {
  title: string;
  description: string;
  icon: React.ReactNode;
}

export interface Experience {
  period: string;
  role: string;
  company: string;
  description: string;
}

import React from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './pages/Home';
import Booking from './pages/Booking';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

const App: React.FC = () => {
  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <Navbar />
        <main className="flex-grow pt-20">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/book" element={<Booking />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'About', path: '/#about' },
    { name: 'Credentials', path: '/#credentials' },
    { name: 'Specialties', path: '/#specialties' },
    { name: 'Experience', path: '/#experience' },
  ];

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md py-4' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-2">
            <span className={`text-2xl font-serif font-bold ${scrolled ? 'text-darkGreen' : 'text-gray-900'}`}>CoachingByLene</span>
          </Link>

          {/* Desktop Links */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.path.startsWith('/#') ? link.path.substring(1) : link.path}
                className={`text-sm font-medium transition-colors hover:text-darkGreen ${scrolled ? 'text-gray-600' : 'text-gray-800'}`}
              >
                {link.name}
              </a>
            ))}
            <Link
              to="/book"
              className="bg-darkGreen text-white px-6 py-2 rounded-full text-sm font-semibold transition-transform hover:scale-105 active:scale-95"
            >
              Book Appointment
            </Link>
          </div>

          {/* Mobile Toggle */}
          <div className="md:hidden">
            <button onClick={() => setIsOpen(!isOpen)} className="text-gray-600 p-2">
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white shadow-lg absolute top-full left-0 w-full animate-in fade-in slide-in-from-top-4 duration-200">
          <div className="px-4 pt-2 pb-6 space-y-2">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.path.startsWith('/#') ? link.path.substring(1) : link.path}
                className="block px-3 py-4 text-base font-medium text-gray-600 hover:text-darkGreen hover:bg-gray-50 rounded-md"
                onClick={() => setIsOpen(false)}
              >
                {link.name}
              </a>
            ))}
            <Link
              to="/book"
              className="block w-full text-center bg-darkGreen text-white px-6 py-4 rounded-md text-base font-semibold"
              onClick={() => setIsOpen(false)}
            >
              Book Appointment
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Calendar, Clock, User, Mail, MessageSquare, CheckCircle, ArrowLeft } from 'lucide-react';
import { BookingFormData } from '../types';
import { Link } from 'react-router-dom';

const Booking: React.FC = () => {
  const [formData, setFormData] = useState<BookingFormData>({
    fullName: '',
    email: '',
    day: '',
    time: '',
    description: ''
  });
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
  const times = [
    '09:00 AM', '10:00 AM', '11:00 AM', '12:00 PM', 
    '01:00 PM', '02:00 PM', '03:00 PM', '04:00 PM'
  ];

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setIsSubmitted(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 1500);
  };

  if (isSubmitted) {
    return (
      <div className="min-h-[80vh] flex flex-col items-center justify-center p-4">
        <div className="bg-white p-12 rounded-3xl shadow-2xl max-w-lg w-full text-center space-y-8 animate-in zoom-in duration-300 border border-primary/20">
          <div className="w-24 h-24 bg-primary/20 text-darkGreen rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle size={48} />
          </div>
          <h2 className="text-3xl font-serif text-gray-900">Booking Requested!</h2>
          <p className="text-gray-600 text-lg leading-relaxed">
            Thank you, <span className="font-bold">{formData.fullName}</span>. Lene will review your request for <span className="font-bold">{formData.day}</span> at <span className="font-bold">{formData.time}</span> and reach out to you via email shortly.
          </p>
          <div className="pt-6">
            <Link 
              to="/" 
              className="inline-block bg-darkGreen text-white px-8 py-3 rounded-full font-bold hover:bg-[#2d5e43] transition-all"
            >
              Return to Home
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-softBeige min-h-screen py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-4xl mx-auto">
        {/* Header Section */}
        <div className="mb-12 flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div className="space-y-2">
            <Link to="/" className="flex items-center gap-2 text-darkGreen font-semibold hover:underline mb-4">
              <ArrowLeft size={16} />
              Back to site
            </Link>
            <h1 className="text-4xl md:text-5xl font-serif text-gray-900">Book an Appointment</h1>
            <p className="text-gray-600 text-lg">Schedule your introductory session or coaching meeting.</p>
          </div>
          <div className="hidden lg:block">
            <div className="bg-white px-6 py-4 rounded-2xl border border-primary/20 shadow-sm">
              <p className="text-xs font-bold text-darkGreen uppercase tracking-widest mb-2">Available Hours</p>
              <p className="text-sm font-medium text-gray-700">Mon - Fri: 09:00 - 16:00</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Form Side */}
          <div className="lg:col-span-2">
            <form onSubmit={handleSubmit} className="bg-white rounded-3xl shadow-xl p-8 md:p-10 space-y-8 border border-primary/10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Full Name */}
                <div className="space-y-2">
                  <label htmlFor="fullName" className="text-sm font-bold text-gray-700 flex items-center gap-2 uppercase tracking-wide">
                    <User size={14} className="text-darkGreen" />
                    Full Name
                  </label>
                  <input
                    required
                    type="text"
                    id="fullName"
                    name="fullName"
                    value={formData.fullName}
                    onChange={handleInputChange}
                    placeholder="Enter your name"
                    className="w-full px-5 py-4 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl transition-all text-gray-900 placeholder:text-gray-400"
                  />
                </div>

                {/* Email Address */}
                <div className="space-y-2">
                  <label htmlFor="email" className="text-sm font-bold text-gray-700 flex items-center gap-2 uppercase tracking-wide">
                    <Mail size={14} className="text-darkGreen" />
                    Email Address
                  </label>
                  <input
                    required
                    type="email"
                    id="email"
                    name="email"
                    value={formData.email}
                    onChange={handleInputChange}
                    placeholder="you@example.com"
                    className="w-full px-5 py-4 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl transition-all text-gray-900 placeholder:text-gray-400"
                  />
                </div>

                {/* Day */}
                <div className="space-y-2">
                  <label htmlFor="day" className="text-sm font-bold text-gray-700 flex items-center gap-2 uppercase tracking-wide">
                    <Calendar size={14} className="text-darkGreen" />
                    Appointment Day
                  </label>
                  <select
                    required
                    id="day"
                    name="day"
                    value={formData.day}
                    onChange={handleInputChange}
                    className="w-full px-5 py-4 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl transition-all text-gray-900 appearance-none cursor-pointer"
                  >
                    <option value="" disabled>Select a weekday</option>
                    {days.map(day => <option key={day} value={day}>{day}</option>)}
                  </select>
                </div>

                {/* Time */}
                <div className="space-y-2">
                  <label htmlFor="time" className="text-sm font-bold text-gray-700 flex items-center gap-2 uppercase tracking-wide">
                    <Clock size={14} className="text-darkGreen" />
                    Appointment Time
                  </label>
                  <select
                    required
                    id="time"
                    name="time"
                    value={formData.time}
                    onChange={handleInputChange}
                    className="w-full px-5 py-4 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl transition-all text-gray-900 appearance-none cursor-pointer"
                  >
                    <option value="" disabled>Select a time</option>
                    {times.map(time => <option key={time} value={time}>{time}</option>)}
                  </select>
                </div>
              </div>

              {/* Description */}
              <div className="space-y-2">
                <label htmlFor="description" className="text-sm font-bold text-gray-700 flex items-center gap-2 uppercase tracking-wide">
                  <MessageSquare size={14} className="text-darkGreen" />
                  Description / Reason for Coaching
                </label>
                <textarea
                  id="description"
                  name="description"
                  rows={4}
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="How can coaching help you? Briefly describe your goals..."
                  className="w-full px-5 py-4 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl transition-all text-gray-900 placeholder:text-gray-400 resize-none"
                ></textarea>
              </div>

              {/* Submit */}
              <button
                type="submit"
                disabled={isSubmitting}
                className={`w-full bg-darkGreen text-white py-5 rounded-xl font-bold text-lg shadow-xl shadow-darkGreen/20 hover:bg-[#2d5e43] transition-all transform active:scale-[0.98] ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
              >
                {isSubmitting ? 'Requesting...' : 'Book Appointment'}
              </button>

              <p className="text-xs text-center text-gray-400 mt-4">
                By submitting this form, you agree that Lene Vindelev D. Nielsen can contact you regarding this appointment.
              </p>
            </form>
          </div>

          {/* Info Side */}
          <div className="space-y-8">
            <div className="bg-darkGreen text-white p-8 rounded-3xl space-y-6">
              <h4 className="text-xl font-serif text-primary">Booking Rules</h4>
              <ul className="space-y-4 text-sm">
                <li className="flex gap-3">
                  <CheckCircle size={18} className="text-primary shrink-0" />
                  <span>Only weekdays (Monday to Friday) are available for selection.</span>
                </li>
                <li className="flex gap-3">
                  <CheckCircle size={18} className="text-primary shrink-0" />
                  <span>Appointments can be scheduled between 9:00 AM and 4:00 PM.</span>
                </li>
                <li className="flex gap-3">
                  <CheckCircle size={18} className="text-primary shrink-0" />
                  <span>Please allow 24-48 hours for confirmation of your slot.</span>
                </li>
              </ul>
            </div>

            <div className="bg-white p-8 rounded-3xl border border-primary/20 space-y-4 shadow-sm">
              <h4 className="font-bold text-gray-900">Need Help?</h4>
              <p className="text-sm text-gray-600 leading-relaxed">
                If you encounter any issues with the form or have urgent requests, feel free to reach out via email.
              </p>
              <div className="pt-2">
                <a href="mailto:lene@coachingbylene.dk" className="text-darkGreen font-bold hover:underline">lene@coachingbylene.dk</a>
              </div>
            </div>

            <div className="p-4 rounded-3xl border-2 border-dashed border-primary/30 text-center">
              <p className="text-sm italic text-gray-500">"Your first chemistry session is always complimentary."</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Booking;

// Added React import to resolve missing namespace 'React' error for React.ReactNode
import React from 'react';

export interface BookingFormData {
  fullName: string;
  email: string;
  day: string;
  time: string;
  description: string;
}

export interface Specialty {
  title: string;
  description: string;
  icon: React.ReactNode;
}

export interface Experience {
  period: string;
  role: string;
  company: string;
  description: string;
}

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Sparkles, Loader2 } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const AiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant', text: string }[]>([
    { role: 'assistant', text: "Hello! I'm Lene's virtual assistant. How can I help you explore coaching possibilities today?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMessage,
        config: {
          systemInstruction: `
            You are a professional and calm AI assistant for Lene Vindelev D. Nielsen, an EMCC Senior Practitioner Coach (CoachingByLene). 
            Your goal is to help potential clients understand her services.

            Key Information about Lene:
            - Location: Denmark (Virtual sessions available globally).
            - Credentials: MSc, EMCC Accredited Senior Practitioner.
            - Focus Areas: Leadership Coaching, Career Transitions, Systemic Team Coaching.
            - Approach: Systemic, solution-focused, values-based, and ethics-driven.
            - Offer: A complimentary chemistry session is always available.
            - Contact: Connect via LinkedIn or book through the website's booking page.

            Guidelines:
            - Maintain a professional, trustworthy, and supportive tone.
            - If asked about booking, direct them to the "Book Appointment" page.
            - Keep responses concise and helpful.
            - Do not invent credentials not listed here.
          `
        }
      });

      const assistantText = response.text || "I apologize, I'm having trouble connecting right now. Please try again or reach out to Lene directly.";
      setMessages(prev => [...prev, { role: 'assistant', text: assistantText }]);
    } catch (error) {
      console.error("Gemini API Error:", error);
      setMessages(prev => [...prev, { role: 'assistant', text: "I'm currently resting. Please feel free to use the booking form or contact Lene via LinkedIn!" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[60]">
      {/* Floating Button */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="bg-darkGreen text-white w-16 h-16 rounded-full shadow-2xl flex items-center justify-center hover:scale-110 transition-transform group"
        >
          <MessageSquare size={28} className="group-hover:rotate-12 transition-transform" />
          <div className="absolute -top-1 -right-1 w-4 h-4 bg-primary rounded-full animate-ping"></div>
        </button>
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className="bg-white w-[350px] md:w-[400px] h-[500px] rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-gray-100 animate-in slide-in-from-bottom-10 duration-300">
          {/* Header */}
          <div className="bg-darkGreen p-5 text-white flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="bg-primary/20 p-2 rounded-xl">
                <Sparkles size={20} className="text-primary" />
              </div>
              <div>
                <p className="font-bold leading-none">Consultation Assistant</p>
                <p className="text-xs text-primary/80 mt-1">Powered by Gemini</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-1 rounded-full transition-colors">
              <X size={24} />
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-grow overflow-y-auto p-5 space-y-4 bg-softBeige/30">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                  m.role === 'user' 
                    ? 'bg-darkGreen text-white rounded-tr-none' 
                    : 'bg-white text-gray-700 shadow-sm border border-gray-100 rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm border border-gray-100">
                  <Loader2 size={18} className="animate-spin text-darkGreen" />
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <form onSubmit={handleSendMessage} className="p-4 bg-white border-t border-gray-100 flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about coaching focus..."
              className="flex-grow px-4 py-2 bg-gray-50 border-0 focus:ring-2 focus:ring-primary rounded-xl text-sm"
            />
            <button
              type="submit"
              disabled={!input.trim() || isLoading}
              className="bg-darkGreen text-white p-2.5 rounded-xl disabled:opacity-50 hover:bg-[#2d5e43] transition-colors"
            >
              <Send size={20} />
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default AiAssistant;

import React from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import Home from './pages/Home';
import Booking from './pages/Booking';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <Navbar />
        <main className="flex-grow pt-20">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/book" element={<Booking />} />
          </Routes>
        </main>
        <Footer />
        <AiAssistant />
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Helper to handle hash scrolling even when on different pages
  const handleHashLink = (e: React.MouseEvent<HTMLAnchorElement>, hash: string) => {
    if (location.pathname === '/') {
      // If on home page, let default anchor behavior work or smooth scroll
      const element = document.querySelector(hash);
      if (element) {
        e.preventDefault();
        element.scrollIntoView({ behavior: 'smooth' });
        setIsOpen(false);
      }
    } else {
      // If on another page (like /book), let the link naturally go to /#hash
      setIsOpen(false);
    }
  };

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'About', hash: '#about' },
    { name: 'Credentials', hash: '#credentials' },
    { name: 'Specialties', hash: '#specialties' },
    { name: 'Experience', hash: '#experience' },
  ];

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md py-4' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-2">
            <span className={`text-2xl font-serif font-bold ${scrolled ? 'text-darkGreen' : 'text-gray-900'}`}>CoachingByLene</span>
          </Link>

          {/* Desktop Links */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              link.path ? (
                <Link
                  key={link.name}
                  to={link.path}
                  className={`text-sm font-medium transition-colors hover:text-darkGreen ${scrolled ? 'text-gray-600' : 'text-gray-800'}`}
                >
                  {link.name}
                </Link>
              ) : (
                <a
                  key={link.name}
                  href={`/#${link.hash}`}
                  onClick={(e) => handleHashLink(e, link.hash!)}
                  className={`text-sm font-medium transition-colors hover:text-darkGreen ${scrolled ? 'text-gray-600' : 'text-gray-800'}`}
                >
                  {link.name}
                </a>
              )
            ))}
            <Link
              to="/book"
              className="bg-darkGreen text-white px-6 py-2 rounded-full text-sm font-semibold transition-transform hover:scale-105 active:scale-95"
            >
              Book Appointment
            </Link>
          </div>

          {/* Mobile Toggle */}
          <div className="md:hidden">
            <button onClick={() => setIsOpen(!isOpen)} className="text-gray-600 p-2">
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white shadow-lg absolute top-full left-0 w-full animate-in fade-in slide-in-from-top-4 duration-200">
          <div className="px-4 pt-2 pb-6 space-y-2">
            {navLinks.map((link) => (
              link.path ? (
                <Link
                  key={link.name}
                  to={link.path}
                  className="block px-3 py-4 text-base font-medium text-gray-600 hover:text-darkGreen hover:bg-gray-50 rounded-md"
                  onClick={() => setIsOpen(false)}
                >
                  {link.name}
                </Link>
              ) : (
                <a
                  key={link.name}
                  href={`/#${link.hash}`}
                  onClick={(e) => handleHashLink(e, link.hash!)}
