          </p>

          <div className="bg-softBeige p-6 rounded-2xl text-left space-y-4">
            <div className="flex justify-between items-center">
              <p className="text-xs font-bold text-darkGreen uppercase tracking-widest">Booking Summary</p>
              <button 
                onClick={() => {
                  const text = `Name: ${formData.fullName}\nEmail: ${formData.email}\nDate: ${formData.day}\nTime: ${formData.time}\nMessage: ${formData.description}`;
                  navigator.clipboard.writeText(text);
                }}
