      setSubmitError("We couldn't process the automatic booking. Please try again or email Lene directly.");
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const constructMailto = () => {
    const recipient = "mironiyuval2@gmail.com";
